Certainly! Setting up a robust and scalable infrastructure using Terraform involves organizing your code into modules that can be easily managed and reused. Below is an example of how you might structure your Terraform files for AWS networking, EKS (Elastic Kubernetes Service), and shared security controls.

### Directory Structure

```
aws_infra/
├── main.tf
├── variables.tf
├── outputs.tf
└── modules/
    ├── vpc/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    ├── eks/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    └── security/
        ├── main.tf
        ├── variables.tf
        └── outputs.tf
```

### `aws_infra/main.tf`
This file will call the modules and set up any global configurations.

```hcl
provider "aws" {
  region = var.aws_region
}

module "vpc" {
  source            = "./modules/vpc"
  cidr_block        = var.vpc_cidr_block
  az_count          = var.az_count
  public_subnets    = var.public_subnets
  private_subnets   = var.private_subnets
  nat_gateway       = true
}

module "eks" {
  source            = "./modules/eks"
  vpc_id            = module.vpc.vpc_id
  subnet_ids        = module.vpc.public_subnet_ids
  cluster_name      = var.eks_cluster_name
  node_group_count  = var.node_group_count
  node_instance_type= var.node_instance_type
}

module "security" {
  source              = "./modules/security"
  vpc_id              = module.vpc.vpc_id
  security_groups     = [module.eks.cluster_security_group]
}
```

### `aws_infra/variables.tf`
Define the variables that will be used across your infrastructure.

```hcl
variable "aws_region" {
  description = "The AWS region to deploy resources."
}

variable "vpc_cidr_block" {
  description = "CIDR block for VPC."
}

variable "az_count" {
  description = "Number of availability zones."
}

variable "public_subnets" {
  description = "List of public subnets."
}

variable "private_subnets" {
  description = "List of private subnets."
}

variable "eks_cluster_name" {
  description = "Name for the EKS cluster."
}

variable "node_group_count" {
  description = "Number of node groups in the EKS cluster."
}

variable "node_instance_type" {
  description = "Instance type for EKS worker nodes."
}
```

### `aws_infra/outputs.tf`
Define outputs that you might want to reference elsewhere or use for monitoring.

```hcl
output "vpc_id" {
  value = module.vpc.vpc_id
}

output "eks_cluster_endpoint" {
  value = module.eks.cluster_endpoint
}

output "security_group_ids" {
  value = module.security.security_group_ids
}
```

### `aws_infra/modules/vpc/main.tf`
Define the VPC and subnets.

```hcl
resource "aws_vpc" "main" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = true
}

resource "aws_subnet" "public" {
  count                = length(var.public_subnets)
  vpc_id               = aws_vpc.main.id
  cidr_block           = element(var.public_subnets, count.index)
  availability_zone    = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
}

resource "aws_subnet" "private" {
  count                = length(var.private_subnets)
  vpc_id               = aws_vpc.main.id
  cidr_block           = element(var.private_subnets, count.index)
  availability_zone    = data.aws_availability_zones.available.names[count.index]
}
```

### `aws_infra/modules/vpc/variables.tf`
Define the variables for VPC module.

```hcl
variable "cidr_block" {
  description = "CIDR block for VPC."
}

variable "public_subnets" {
  description = "List of public subnets."
}

variable "private_subnets" {
  description = "List of private subnets."
}
```

### `aws_infra/modules/vpc/outputs.tf`
Define outputs for the VPC module.

```hcl
output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_ids" {
  value = aws_subnet.public.*.id
}

output "private_subnet_ids" {
  value = aws_subnet.private.*.id
}
```

### `aws_infra/modules/eks/main.tf`
Define the EKS cluster.

```hcl
resource "aws_eks_cluster" "main" {
  name     = var.cluster_name
  role_arn = data.aws_iam_role.main.arn

  vpc_config {
    subnet_ids = var.subnet_ids
  }
}

data "aws_iam_role" "main" {
  name = "${var.cluster_name}-cluster"
}
```

### `aws_infra/modules/eks/variables.tf`
Define the variables for EKS module.

```hcl
variable "vpc_id" {
  description = "ID of the VPC."
}

variable "subnet_ids" {
  description = "List of subnet IDs."
}

variable "cluster_name" {
  description = "Name for the EKS cluster."
}

variable "node_group_count" {
  description = "Number of node groups in the EKS cluster."
}

variable "node_instance_type" {
  description = "Instance type for EKS worker nodes."
}
```

### `aws_infra/modules/eks/outputs.tf`
Define outputs for the EKS module.

```hcl
output "cluster_endpoint" {
  value = aws_eks_cluster.main.endpoint
}

output "cluster_security_group" {
  value = aws_eks_cluster.main.security_group_ids[0]
}
```

### `aws_infra/modules/security/main.tf`
Define security groups and other security controls.

```hcl
resource "aws_security_group" "main" {
  name        = var.vpc_id
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group_rule" "main" {
  count         = length(var.security_groups)
  type          = "ingress"
  security_group_id = element(var.security_groups, count.index)

  from_port   = 0
  to_port     = 0
  protocol    = "-1"
  cidr_blocks = ["0.0.0.0/0"]
}
```

### `aws_infra/modules/security/variables.tf`
Define the variables for security module.

```hcl
variable "vpc_id" {
  description = "ID of the VPC."
}

variable "security_groups" {
  description = "List of security groups to apply rules on."
}
```

### `aws_infra/modules/security/outputs.tf`
Define outputs for the security module.

```hcl
output "security_group_ids" {
  value = aws_security_group.main.id
}
```

This structure provides a clean and modular approach to setting up your AWS infrastructure using Terraform. Each module is responsible for its own resources, making it easier to manage and scale as needed.

To address your concerns about accidental drift from manual console changes and to ensure compliance with the new tagging requirements and post-bootstrap cluster add-on installation, you can follow these steps:

### Step 1: Ensure Tagging Compliance in Terraform

Ensure that all resources are tagged appropriately as per the new rules.

#### Example VPC Module (`modules/vpc/main.tf`)

```hcl
resource "aws_vpc" "main" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = true

  tags = {
    Name        = "${var.account_name}-${var.environment}-vpc"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

resource "aws_subnet" "public" {
  count                = length(var.public_subnets)
  vpc_id               = aws_vpc.main.id
  cidr_block           = element(var.public_subnets, count.index)
  availability_zone    = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name        = "${var.account_name}-${var.environment}-public-subnet-${count.index + 1}"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

resource "aws_subnet" "private" {
  count                = length(var.private_subnets)
  vpc_id               = aws_vpc.main.id
  cidr_block           = element(var.private_subnets, count.index)
  availability_zone    = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name        = "${var.account_name}-${var.environment}-private-subnet-${count.index + 1}"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}
```

### Step 2: Bootstrap EKS Cluster

Ensure the EKS cluster is bootstrapped and tagged appropriately.

#### Example EKS Module (`modules/eks/main.tf`)

```hcl
resource "aws_eks_cluster" "main" {
  name     = var.cluster_name
  role_arn = data.aws_iam_role.main.arn

  vpc_config {
    subnet_ids = var.subnet_ids
  }

  tags = {
    Name        = "${var.account_name}-${var.environment}-eks"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

data "aws_iam_role" "main" {
  name = "${var.cluster_name}-cluster"

  tags = {
    Name        = "${var.account_name}-${var.environment}-eks-iam-role"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}
```

### Step 3: Add Cluster Add-ons After Bootstrap

After the EKS cluster is bootstrapped, you can add the required cluster add-ons using Terraform.

#### Example Configuration in `main.tf`

```hcl
provider "aws" {
  region = var.aws_region
}

module "vpc" {
  source            = "./modules/vpc"
  cidr_block        = var.vpc_cidr_block
  az_count          = var.az_count
  public_subnets    = var.public_subnets
  private_subnets   = var.private_subnets
  nat_gateway       = true

  tags = {
    Name        = "${var.account_name}-${var.environment}-vpc"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

module "eks" {
  source            = "./modules/eks"
  vpc_id            = module.vpc.vpc_id
  subnet_ids        = module.vpc.private_subnet_ids
  cluster_name      = var.eks_cluster_name

  tags = {
    Name        = "${var.account_name}-${var.environment}-eks"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  cluster_ca_certificate = base64decode(module.eks.cluster_cert)
  config_path            = "~/.kube/config"
}

resource "helm_release" "metrics_server" {
  name       = "metrics-server"
  repository = "https://charts.bitnami.com/bitnami"
  chart      = "metrics-server"
  namespace  = "kube-system"

  set {
    name  = "rbac.create"
    value = true
  }

  tags = {
    Name        = "${var.account_name}-${var.environment}-metrics-server"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

resource "helm_release" "ebs_csi_driver" {
  name       = "aws-ebs-csi-driver"
  repository = "https://charts.bitnami.com/bitnami"
  chart      = "aws-ebs-csi-driver"
  namespace  = "kube-system"

  tags = {
    Name        = "${var.account_name}-${var.environment}-ebs-csi-driver"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

resource "helm_release" "external_dns" {
  name       = "external-dns"
  repository = "https://charts.bitnami.com/bitnami"
  chart      = "external-dns"
  namespace  = "kube-system"

  set {
    name  = "provider"
    value = "route53"
  }

  tags = {
    Name        = "${var.account_name}-${var.environment}-external-dns"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}
```

### Step 4: Prevent Drift with Terraform State Management

To prevent drift from manual console changes, ensure you manage your infrastructure state using Terraform and regularly apply updates to enforce the desired configuration.

#### Example `main.tf` for Applying Changes

```hcl
provider "aws" {
  region = var.aws_region
}

module "vpc" {
  source            = "./modules/vpc"
  cidr_block        = var.vpc_cidr_block
  az_count          = var.az_count
  public_subnets    = var.public_subnets
  private_subnets   = var.private_subnets
  nat_gateway       = true

  tags = {
    Name        = "${var.account_name}-${var.environment}-vpc"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

module "eks" {
  source            = "./modules/eks"
  vpc_id            = module.vpc.vpc_id
  subnet_ids        = module.vpc.private_subnet_ids
  cluster_name      = var.eks_cluster_name

  tags = {
    Name        = "${var.account_name}-${var.environment}-eks"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  cluster_ca_certificate = base64decode(module.eks.cluster_cert)
  config_path            = "~/.kube/config"
}

resource "helm_release" "metrics_server" {
  name       = "metrics-server"
  repository = "https://charts.bitnami.com/bitnami"
  chart      = "metrics-server"
  namespace  = "kube-system"

  set {
    name  = "rbac.create"
    value = true
  }

  tags = {
    Name        = "${var.account_name}-${var.environment}-metrics-server"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

resource "helm_release" "ebs_csi_driver" {
  name       = "aws-ebs-csi-driver"
  repository = "https://charts.bitnami.com/bitnami"
  chart      = "aws-ebs-csi-driver"
  namespace  = "kube-system"

  tags = {
    Name        = "${var.account_name}-${var.environment}-ebs-csi-driver"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}

resource "helm_release" "external_dns" {
  name       = "external-dns"
  repository = "https://charts.bitnami.com/bitnami"
  chart      = "external-dns"
  namespace  = "kube-system"

  set {
    name  = "provider"
    value = "route53"
  }

  tags = {
    Name        = "${var.account_name}-${var.environment}-external-dns"
    Environment = var.environment
    Owner       = var.team_name
    CostCenter  = var.cost_center
  }
}
```

### Step 5: Regularly Apply Terraform Changes

Regularly run `terraform plan` and `terraform apply` to ensure that any manual changes made via the console are reverted back to the desired state defined in your Terraform configuration.

#### Example Commands

```sh
terraform init
terraform plan -var-file=dev/terraform.tfvars
terraform apply -var-file=dev/terraform.tfvars
```

### Summary

By ensuring all resources are tagged appropriately and using Terraform to manage cluster add-ons after the EKS cluster is bootstrapped, you can prevent accidental drift from manual console changes. Regularly applying Terraform updates will help maintain compliance with your infrastructure requirements.

This approach ensures that your infrastructure remains consistent and adheres to the tagging rules set by your FinOps team while also managing cluster add-ons effectively.

To ensure robust retention and immutability of Docker images in Amazon Elastic Container Registry (ECR), it's important to implement appropriate policies. Here are some recommended ECR policies:

### 1. **Retention Policies**
Retention policies help manage the lifecycle of your images by automatically deleting them after a specified period.

#### Example Retention Policy

```json
{
    "rules": [
        {
            "rulePriority": 1,
            "description": "Delete untagged images older than 30 days",
            "selection": {
                "status": "ENABLED",
                "countType": "NONE",
                "tagStatus": "UNTAGGED",
                "tagPrefixList": [],
                "prefix": "",
                "creationTimeBefore": "2023-10-01T00:00:00Z"
            },
            "action": {
                "type": "DELETE"
            }
        },
        {
            "rulePriority": 2,
            "description": "Delete images tagged with 'latest' older than 90 days",
            "selection": {
                "status": "ENABLED",
                "countType": "NONE",
                "tagStatus": "ANY",
                "tagPrefixList": ["latest"],
                "prefix": "",
                "creationTimeBefore": "2023-10-01T00:00:00Z"
            },
            "action": {
                "type": "DELETE"
            }
        }
    ]
}
```

### 2. **Immutability Policies**
Immutability policies ensure that once an image is pushed to ECR, it cannot be modified or deleted. This helps maintain the integrity and consistency of your images.

#### Example Immutability Policy

```json
{
    "rules": [
        {
            "rulePriority": 1,
            "description": "Prevent deletion of any image",
            "selection": {
                "status": "ENABLED",
                "countType": "NONE",
                "tagStatus": "ANY",
                "tagPrefixList": [],
                "prefix": "",
                "creationTimeBefore": ""
            },
            "action": {
                "type": "READONLY"
            }
        }
    ]
}
```

### 3. **Combining Retention and Immutability**
You can combine both retention and immutability policies to ensure that images are retained for a certain period but cannot be modified or deleted during that time.

#### Example Combined Policy

```json
{
    "rules": [
        {
            "rulePriority": 1,
            "description": "Prevent deletion of any image",
            "selection": {
                "status": "ENABLED",
                "countType": "NONE",
                "tagStatus": "ANY",
                "tagPrefixList": [],
                "prefix": "",
                "creationTimeBefore": ""
            },
            "action": {
                "type": "READONLY"
            }
        },
        {
            "rulePriority": 2,
            "description": "Delete untagged images older than 30 days",
            "selection": {
                "status": "ENABLED",
                "countType": "NONE",
                "tagStatus": "UNTAGGED",
                "tagPrefixList": [],
                "prefix": "",
                "creationTimeBefore": "2023-10-01T00:00:00Z"
            },
            "action": {
                "type": "DELETE"
            }
        },
        {
            "rulePriority": 3,
            "description": "Delete images tagged with 'latest' older than 90 days",
            "selection": {
                "status": "ENABLED",
                "countType": "NONE",
                "tagStatus": "ANY",
                "tagPrefixList": ["latest"],
                "prefix": "",
                "creationTimeBefore": "2023-10-01T00:00:00Z"
            },
            "action": {
                "type": "DELETE"
            }
        }
    ]
}
```

### 4. **Applying Policies via AWS CLI or SDK**
You can apply these policies using the `aws ecr put-lifecycle-policy` command.

#### Example Command

```sh
aws ecr put-lifecycle-policy --registry-id <AWS_ACCOUNT_ID> --repository-name <REPOSITORY_NAME> --lifecycle-policy-text file://path/to/lifecycle_policy.json
```

### 5. **IAM Policies**
Ensure that IAM policies restrict access to ECR operations that could violate immutability and retention rules.

#### Example IAM Policy

```json
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "ecr:GetLifecyclePolicy",
                "ecr:PutLifecyclePolicy"
            ],
            "Resource": "arn:aws:ecr:<REGION>:<AWS_ACCOUNT_ID>:repository/<REPOSITORY_NAME>"
        },
        {
            "Effect": "Deny",
            "Action": [
                "ecr:DeleteRepository",
                "ecr:BatchDeleteImage"
            ],
            "Condition": {
                "StringEquals": {
                    "aws:ResourceTag/Immutability": ["true"]
                }
            },
            "Resource": "arn:aws:ecr:<REGION>:<AWS_ACCOUNT_ID>:repository/<REPOSITORY_NAME>"
        }
    ]
}
```

### Summary

By implementing retention and immutability policies in ECR, you can ensure that your Docker images are managed effectively while maintaining their integrity. This approach helps prevent accidental deletion or modification of critical images and ensures they are retained for the necessary period.

Using a combination of lifecycle policies and IAM restrictions will provide robust governance over your container images in ECR.

