  name        = var.sg_name
  description = "Security group for EKS"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge(
    local.common_tags,
    map("Name", "${var.environment}-${var.sg_name}")
  )
}

locals {
  common_tags = {
    Environment   = var.environment
    Owner         = var.team_name
    CostCenter    = var.cost_center
    Compliance    = "SOC2"
  }
}
```

