### Module Structure

#### VPC Module (`modules/vpc`)

##### `main.tf`
This file will define the resources for creating a VPC and subnets.

```hcl
resource "aws_vpc" "vpc" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = true
}

resource "aws_subnet" "public_subnets" {
  count             = length(var.public_subnets)
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = element(var.public_subnets, count.index)
  availability_zone = format("%s%s", var.region, ["a", "b", "c"][count.index])
}

resource "aws_subnet" "private_subnets" {
  count             = length(var.private_subnets)
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = element(var.private_subnets, count.index)
  availability_zone = format("%s%s", var.region, ["a", "b", "c"][count.index])
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_nat_gateway" "nat_gateways" {
  count             = length(var.public_subnets)
  allocation_id     = data.aws_eip.nat[count.index].id
  subnet_id         = aws_subnet.public_subnets[count.index].id

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route_table" "public_routes" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route" "internet_gateway_route" {
  count             = length(var.public_subnets)
  route_table_id    = aws_route_table.public_routes[count.index].id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id        = aws_internet_gateway.igw.id
}

resource "aws_route_table_association" "public_subnet_assoc" {
  count             = length(var.public_subnets)
  subnet_id         = aws_subnet.public_subnets[count.index].id
  route_table_id    = aws_route_table.public_routes[count.index].id
}
```

